import{_ as i,o as e,c as a,a3 as t}from"./chunks/framework.aYYe0dfI.js";const c=JSON.parse('{"title":"clore::net::icontains","description":"The function clore::net::icontains implements a case‑insensitive substring search using a straightforward brute‑force algorithm. It first performs an early‑exit check: if the length of needle exceeds the length of haystack, it returns false immediately. Otherwise, it iterates over each possible starting index i from 0 to haystack.size() - needle.size() inclusive. For each i, it sets a match flag to true and enters an inner loop over index j from 0 to needle.size() - 1. Inside the inner loop it compares haystack[i + j] and needle[j] after converting both to lowercase via std::tolower(static_cast<unsigned char>(…)). If any pair differs, match is set to false and the inner loop is broken. After the inner loop, if match remains true the function returns true immediately. If no starting position yields a full match, the function returns false. The only external dependency is std::tolower from the C++ standard library; no project‑specific utilities are used.","frontmatter":{"title":"clore::net::icontains","description":"The function clore::net::icontains implements a case‑insensitive substring search using a straightforward brute‑force algorithm. It first performs an early‑exit check: if the length of needle exceeds the length of haystack, it returns false immediately. Otherwise, it iterates over each possible starting index i from 0 to haystack.size() - needle.size() inclusive. For each i, it sets a match flag to true and enters an inner loop over index j from 0 to needle.size() - 1. Inside the inner loop it compares haystack[i + j] and needle[j] after converting both to lowercase via std::tolower(static_cast<unsigned char>(…)). If any pair differs, match is set to false and the inner loop is broken. After the inner loop, if match remains true the function returns true immediately. If no starting position yields a full match, the function returns false. The only external dependency is std::tolower from the C++ standard library; no project‑specific utilities are used.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/protocol/functions/icontains.md","filePath":"en/clore/modules/protocol/functions/icontains.md"}'),n={name:"clore/modules/protocol/functions/icontains.md"};function l(h,s,r,k,p,o){return e(),a("div",null,[...s[0]||(s[0]=[t("",16)])])}const E=i(n,[["render",l]]);export{c as __pageData,E as default};
